# Simplified ticket handler (AWS SAM entry point)
import json, os, boto3, anthropic

dynamo = boto3.resource("dynamodb").Table(os.environ["SESSIONS_TABLE"])
sqs    = boto3.client("sqs")
llm    = anthropic.Anthropic()

TICKET_TOOLS = [
    {
        "name": "lookup_documentation",
        "description": "Search internal docs for answers to product questions.",
        "input_schema": {"type":"object","properties":{"query":{"type":"string"}},"required":["query"]},
    },
    {
        "name": "get_customer_info",
        "description": "Retrieve subscription plan and account status by email.",
        "input_schema": {"type":"object","properties":{"email":{"type":"string"}},"required":["email"]},
    },
]

SYSTEM = (
    "You are a customer support agent. After gathering information, output JSON: "
    "{resolution: string, confidence: 0.0-1.0, auto_resolve: bool}. "
    "Only set auto_resolve=true when fully confident."
)

def handler(event, context):
    body       = json.loads(event["Records"][0]["body"])
    session_id = f"ticket-{body['ticket_id']}"

    resp  = dynamo.get_item(Key={"session_id": session_id})
    state = resp.get("Item") or {"session_id": session_id, "messages": [], "step": 0}

    if state["step"] == 0:
        state["messages"].append({
            "role": "user",
            "content": f"Customer: {body['requester_email']}\nTicket:\n{body['ticket_body']}",
        })

    response = llm.messages.create(
        model="claude-opus-4-5", max_tokens=2048,
        system=SYSTEM, tools=TICKET_TOOLS, messages=state["messages"],
    )

    if response.stop_reason == "tool_use":
        state["messages"].append({"role": "assistant", "content": response.content})
        state["step"] += 1
        dynamo.put_item(Item=state)
        # Dispatch tool runners and re-enqueue (omitted for brevity)
        return

    text   = next(b.text for b in response.content if hasattr(b, "text"))
    result = json.loads(text) if text.strip().startswith("{") else {"resolution": text, "confidence": 0.5, "auto_resolve": False}

    if result.get("auto_resolve") and result.get("confidence", 0) >= 0.85:
        print(f"Auto-resolving ticket {body['ticket_id']}")
        # post_zendesk_reply(body["ticket_id"], result["resolution"])
    else:
        print(f"Flagged for review: {result['resolution'][:80]}...")

