import time, random, anthropic

def call_llm_with_backoff(client, **kwargs):
    for attempt in range(5):
        try:
            return client.messages.create(**kwargs)
        except anthropic.RateLimitError:
            wait = (2 ** attempt) + random.uniform(0, 1)
            time.sleep(wait)
    raise RuntimeError("LLM rate limit exhausted after 5 retries")

from aws_lambda_powertools.utilities.idempotency import (
    idempotent, DynamoDBPersistenceLayer, IdempotencyConfig
)

persistence_store = DynamoDBPersistenceLayer(table_name=os.environ["IDEMPOTENCY_TABLE"])
config = IdempotencyConfig(event_key_jmespath="Records[0].body")

@idempotent(persistence_store=persistence_store, config=config)
def handler(event, context):
    # If this exact event was already processed successfully,
    # the decorator returns the cached result without re-executing.
    body = json.loads(event["Records"][0]["body"])
    return process_agent_step(body)
